#!/usr/bin/env python3
"""audit_codeowners_coverage.py — fail if GenAI paths lack CODEOWNERS entries."""
import subprocess, re, sys
from pathlib import Path

# Paths that MUST have an explicit CODEOWNERS entry
REQUIRED_COVERAGE = [
    "prompts/",
    "prompts/system/",
    "tools/schemas/",
    "agents/",
    "evals/",
    ".github/CODEOWNERS",
]

def load_codeowners(path: Path) -> dict[str, str]:
    """Return {pattern: owners} from CODEOWNERS, last-match-wins order."""
    entries = {}
    for line in path.read_text().splitlines():
        line = line.strip()
        if not line or line.startswith("#"):
            continue
        parts = line.split()
        if len(parts) >= 2:
            entries[parts[0]] = " ".join(parts[1:])
    return entries

def check_coverage(entries: dict[str, str]) -> list[str]:
    missing = []
    for path in REQUIRED_COVERAGE:
        if path not in entries:
            missing.append(path)
    return missing

def check_empty_owners(entries: dict[str, str]) -> list[str]:
    """Detect entries that explicitly set no owners (silent bypass)."""
    return [p for p, owners in entries.items() if not owners.strip()]

if __name__ == "__main__":
    codeowners = Path(".github/CODEOWNERS")
    if not codeowners.exists():
        print("ERROR: .github/CODEOWNERS not found", file=sys.stderr)
        sys.exit(1)

    entries = load_codeowners(codeowners)
    missing = check_coverage(entries)
    silent_bypass = check_empty_owners(entries)

    if missing:
        print(f"FAIL: {len(missing)} required paths have no CODEOWNERS entry:")
        for p in missing:
            print(f"  - {p}")

    if silent_bypass:
        print(f"FAIL: {len(silent_bypass)} paths have empty owner lists (silent bypass):")
        for p in silent_bypass:
            print(f"  - {p}")

    if missing or silent_bypass:
        sys.exit(1)

    print(f"OK: {len(REQUIRED_COVERAGE)} required paths all have owners")

#!/usr/bin/env python3
"""check_codeowners_freshness.py — detect stale team slugs and missing paths."""
import subprocess, sys
from pathlib import Path

CODEOWNERS = Path(".github/CODEOWNERS")


def get_repo_teams() -> set[str]:
    try:
        result = subprocess.run(
            ["gh", "api", "orgs/{owner}/teams", "--paginate", "--jq", ".[].slug"],
            capture_output=True, text=True, check=True
        )
        return {f"@{line.strip()}" for line in result.stdout.splitlines() if line.strip()}
    except subprocess.CalledProcessError:
        print("WARNING: Could not fetch org teams")
        return set()


def parse_owners(text: str) -> set[str]:
    owners = set()
    for line in text.splitlines():
        line = line.strip()
        if not line or line.startswith("#"):
            continue
        parts = line.split()
        for p in parts[1:]:
            if p.startswith("@"):
                owners.add(p)
    return owners


def get_existing_genai_paths() -> list[str]:
    important_dirs = ["prompts", "tools", "agents", "evals", "infra", "shared"]
    return [d for d in important_dirs if Path(d).is_dir()]


if __name__ == "__main__":
    text = CODEOWNERS.read_text()
    referenced_owners = parse_owners(text)
    real_teams = get_repo_teams()

    stale = [o for o in referenced_owners
             if real_teams and o.startswith("@") and "/" not in o and o not in real_teams]

    uncovered = [
        path for path in get_existing_genai_paths()
        if not any(path in line for line in text.splitlines() if not line.startswith("#"))
    ]

    if stale:
        print(f"STALE owners (no longer exist in org): {stale}")
    if uncovered:
        print(f"UNCOVERED directories: {uncovered}")

    if stale or uncovered:
        sys.exit(1)
    print("CODEOWNERS freshness check passed")
